            ? webLink.publicBaseUrl
            : DEFAULT_CONFIG.voice.webLink.publicBaseUrl,
        includeInMessage:
          webLink.includeInMessage ?? DEFAULT_CONFIG.voice.webLink.includeInMessage,
        linkTemplate:
